import{_ as r,C as o,o as a,c as e,ae as n,E as s}from"./chunks/framework.DNDrU9L4.js";const _=JSON.parse('{"title":"자주 틀리는 표현","description":"","frontmatter":{},"headers":[],"relativePath":"japanese/beginner/common-mistakes.md","filePath":"japanese/beginner/common-mistakes.md"}'),h={name:"japanese/beginner/common-mistakes.md"};function i(g,t,l,b,c,p){const d=o("Quiz");return a(),e("div",null,[t[0]||(t[0]=n('<h1 id="자주-틀리는-표현" tabindex="-1">자주 틀리는 표현 <a class="header-anchor" href="#자주-틀리는-표현" aria-label="Permalink to &quot;자주 틀리는 표현&quot;">​</a></h1><p>한국인이 일본어를 배울 때 자주 혼동하는 표현들을 정리했어요!</p><h2 id="_1-は-vs-が" tabindex="-1">1. は vs が <a class="header-anchor" href="#_1-は-vs-が" aria-label="Permalink to &quot;1. は vs が&quot;">​</a></h2><p>가장 많이 헷갈리는 조사!</p><table tabindex="0"><thead><tr><th>상황</th><th>올바른 표현</th><th>설명</th></tr></thead><tbody><tr><td>자기소개</td><td>私<strong>は</strong>ファンです</td><td>주제 제시 (나는~)</td></tr><tr><td>누구냐고 물을 때</td><td>誰<strong>が</strong>推しですか？</td><td>새 정보 강조 (누가~?)</td></tr><tr><td>좋아하는 것</td><td>遥花ちゃん<strong>が</strong>好きです</td><td>감정의 대상은 が</td></tr><tr><td>설명할 때</td><td>遥花ちゃん<strong>は</strong>かわいいです</td><td>주제에 대해 설명</td></tr></tbody></table><blockquote><p>💡 핵심: <strong>は</strong> = 이미 알고 있는 주제, <strong>が</strong> = 새로운 정보/강조</p></blockquote><h2 id="_2-に-vs-で" tabindex="-1">2. に vs で <a class="header-anchor" href="#_2-に-vs-で" aria-label="Permalink to &quot;2. に vs で&quot;">​</a></h2><table tabindex="0"><thead><tr><th>예문</th><th>조사</th><th>이유</th></tr></thead><tbody><tr><td>ライブ<strong>に</strong>行く</td><td>に</td><td>이동의 목적지</td></tr><tr><td>渋谷<strong>で</strong>ライブを見る</td><td>で</td><td>동작이 일어나는 장소</td></tr><tr><td>3時<strong>に</strong>始まる</td><td>に</td><td>시간</td></tr><tr><td>電車<strong>で</strong>行く</td><td>で</td><td>수단</td></tr></tbody></table><blockquote><p>💡 핵심: <strong>に</strong> = 도착점/시간, <strong>で</strong> = 동작 장소/수단</p></blockquote><h2 id="_3-발음-주의" tabindex="-1">3. 발음 주의 <a class="header-anchor" href="#_3-발음-주의" aria-label="Permalink to &quot;3. 발음 주의&quot;">​</a></h2><table tabindex="0"><thead><tr><th>문자</th><th>잘못된 발음</th><th>올바른 발음</th><th>설명</th></tr></thead><tbody><tr><td>は (조사)</td><td>ha</td><td><strong>wa</strong></td><td>조사일 때만 wa</td></tr><tr><td>を</td><td>wo</td><td><strong>o</strong></td><td>거의 o로 발음</td></tr><tr><td>ん</td><td>n</td><td><strong>상황에 따라</strong></td><td>뒤 글자에 따라 m/n/ng</td></tr><tr><td>し</td><td>si</td><td><strong>shi</strong></td><td>영어 sh 발음</td></tr><tr><td>つ</td><td>tu</td><td><strong>tsu</strong></td><td>ts 발음</td></tr><tr><td>ふ</td><td>hu</td><td><strong>fu</strong></td><td>입술 불며 f 비슷</td></tr></tbody></table><h2 id="_4-い형-vs-な형-혼동" tabindex="-1">4. い형 vs な형 혼동 <a class="header-anchor" href="#_4-い형-vs-な형-혼동" aria-label="Permalink to &quot;4. い형 vs な형 혼동&quot;">​</a></h2><p>겉모습은 비슷한데 종류가 다른 형용사!</p><table tabindex="0"><thead><tr><th>단어</th><th>종류</th><th>주의점</th></tr></thead><tbody><tr><td>かわいい</td><td>い형</td><td>○ 정상적인 い형</td></tr><tr><td>きれい</td><td><strong>な형</strong></td><td>✗ い로 끝나지만 な형!</td></tr><tr><td>嫌い (키라이)</td><td><strong>な형</strong></td><td>✗ い로 끝나지만 な형!</td></tr><tr><td>大きい</td><td>い형</td><td>○ 정상적인 い형</td></tr><tr><td>有名 (유메이)</td><td>な형</td><td>○ 정상적인 な형</td></tr></tbody></table><blockquote><p>💡 「きれい」「嫌い」는 い로 끝나지만 な형용사! 틀리기 쉬우니 외우세요.</p></blockquote><h2 id="_5-ます형-과거-혼동" tabindex="-1">5. ます형 과거 혼동 <a class="header-anchor" href="#_5-ます형-과거-혼동" aria-label="Permalink to &quot;5. ます형 과거 혼동&quot;">​</a></h2><table tabindex="0"><thead><tr><th>형태</th><th>올바른</th><th>흔한 실수</th></tr></thead><tbody><tr><td>긍정 과거</td><td>行き<strong>ました</strong></td><td>行き<strong>ますた</strong> ✗</td></tr><tr><td>부정 현재</td><td>行き<strong>ません</strong></td><td>行き<strong>ますん</strong> ✗</td></tr><tr><td>부정 과거</td><td>行き<strong>ませんでした</strong></td><td>行き<strong>ましたない</strong> ✗</td></tr></tbody></table><h2 id="_6-「大丈夫」만능-아님" tabindex="-1">6. 「大丈夫」만능 아님! <a class="header-anchor" href="#_6-「大丈夫」만능-아님" aria-label="Permalink to &quot;6. 「大丈夫」만능 아님!&quot;">​</a></h2><p>한국어 &quot;괜찮아&quot;처럼 만능이 아니에요.</p><table tabindex="0"><thead><tr><th>상황</th><th>일본어</th><th>한국어</th></tr></thead><tbody><tr><td>거절</td><td>大丈夫です</td><td>괜찮습니다 (됐어요)</td></tr><tr><td>걱정</td><td>大丈夫？</td><td>괜찮아?</td></tr><tr><td>허락</td><td>✗ 大丈夫</td><td>○ いいですよ (돼요)</td></tr></tbody></table><h2 id="_7-숫자-불규칙-읽기" tabindex="-1">7. 숫자 불규칙 읽기 <a class="header-anchor" href="#_7-숫자-불규칙-읽기" aria-label="Permalink to &quot;7. 숫자 불규칙 읽기&quot;">​</a></h2><table tabindex="0"><thead><tr><th>숫자</th><th>흔한 실수</th><th>올바른</th></tr></thead><tbody><tr><td>4시</td><td>しじ ✗</td><td><strong>よじ</strong></td></tr><tr><td>7시</td><td>ななじ ✗</td><td><strong>しちじ</strong></td></tr><tr><td>9시</td><td>きゅうじ ✗</td><td><strong>くじ</strong></td></tr><tr><td>1명</td><td>いちにん ✗</td><td><strong>ひとり</strong></td></tr><tr><td>2명</td><td>ににん ✗</td><td><strong>ふたり</strong></td></tr><tr><td>20일</td><td>にじゅうにち ✗</td><td><strong>はつか</strong></td></tr></tbody></table><h2 id="혼동-퀴즈" tabindex="-1">혼동 퀴즈 <a class="header-anchor" href="#혼동-퀴즈" aria-label="Permalink to &quot;혼동 퀴즈&quot;">​</a></h2>',23)),s(d,{quizId:"common-mistakes",questions:[{q:"「遥花ちゃん（　）好きです」 빈칸은?",options:["は","が","を","に"],answer:1},{q:"「きれい」는 い형? な형?",options:["い형용사","な형용사"],answer:1},{q:"「は」가 조사로 쓰일 때 발음은?",options:["ha","wa","ba","pa"],answer:1},{q:"「渋谷（　）ライブを見る」 빈칸은?",options:["に","で","を","が"],answer:1},{q:"4시의 올바른 읽기는?",options:["しじ","よじ","よんじ","しいじ"],answer:1},{q:"「行きます」의 부정 과거는?",options:["行きますない","行きましたない","行きませんでした","行きますんでした"],answer:2},{q:"1명의 올바른 읽기는?",options:["いちにん","いちめい","ひとり","いちひと"],answer:2},{q:"20일의 올바른 읽기는?",options:["にじゅうにち","はつか","ふつか","にじゅっか"],answer:1}]})])}const q=r(h,[["render",i]]);export{_ as __pageData,q as default};
